style:
.svc-hub {
  font-family: "Space Grotesk", "Inter", sans-serif;
  color: #1b1b1b;
}

.svc-hero {
  background: linear-gradient(135deg, #6b7eea, #6a4dbb);
  border-radius: 22px;
  padding: 28px 32px;
  color: #fff;
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 22px;
  box-shadow: 0 16px 40px rgba(48, 35, 78, 0.3);
  position: relative;
  overflow: hidden;
}

.svc-hero::after {
  content: "";
  position: absolute;
  right: -80px;
  top: -60px;
  width: 240px;
  height: 240px;
  background: radial-gradient(circle, rgba(255,255,255,0.35), rgba(255,255,255,0));
  pointer-events: none;
}

.svc-hero-icon {
  width: 64px;
  height: 64px;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.22);
  backdrop-filter: blur(6px);
  display: grid;
  place-items: center;
  font-size: 30px;
}

.svc-hero-text h2 {
  margin: 0;
  font-size: 26px;
  font-weight: 600;
}

.svc-hero-text p {
  margin: 4px 0 0 0;
  opacity: 0.9;
  font-size: 13px;
}

.svc-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 18px;
}

.svc-tile {
  background: #fff;
  border-radius: 18px;
  padding: 18px;
  display: flex;
  gap: 14px;
  align-items: center;
  text-decoration: none;
  color: inherit;
  box-shadow: 0 10px 24px rgba(17, 24, 39, 0.1);
  border: 1px solid #eef0f4;
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.2s ease;
  position: relative;
}

.svc-tile:hover {
  transform: translateY(-6px);
  box-shadow: 0 16px 32px rgba(17, 24, 39, 0.16);
  border-color: rgba(107, 126, 234, 0.4);
}

.svc-tile-icon {
  width: 54px;
  height: 54px;
  border-radius: 16px;
  display: grid;
  place-items: center;
  font-size: 24px;
  background: #f3f4ff;
  box-shadow: inset 0 0 0 1px rgba(107, 126, 234, 0.15);
}

.svc-tile-master .svc-tile-icon {
  background: linear-gradient(135deg, #eaf2ff, #f5f8ff);
}

.svc-tile-report .svc-tile-icon {
  background: linear-gradient(135deg, #f3ecff, #fbf8ff);
}

.svc-tile-body h4 {
  margin: 0;
  font-size: 16px;
  font-weight: 600;
}

.svc-tile-body p {
  margin: 4px 0 0 0;
  font-size: 12px;
  color: #6b6b6b;
}

.svc-tile-badge {
  position: absolute;
  top: 12px;
  right: 12px;
  font-size: 11px;
  padding: 4px 8px;
  border-radius: 999px;
  background: rgba(107, 126, 234, 0.12);
  color: #4c5bd4;
  border: 1px solid rgba(107, 126, 234, 0.2);
}

.svc-tile-report .svc-tile-badge {
  background: rgba(106, 77, 187, 0.12);
  color: #6a4dbb;
  border-color: rgba(106, 77, 187, 0.2);
}

.svc-tile-arrow {
  margin-left: auto;
  font-size: 18px;
  color: #9aa0a6;
  transition: transform 0.2s ease, color 0.2s ease;
}

.svc-tile:hover .svc-tile-arrow {
  transform: translateX(4px);
  color: #6b7eea;
}
